<?php
$baseUrl     = rtrim(BASE_URL, '/');
$csrfToken   = htmlspecialchars($_SESSION['csrf_token'] ?? '', ENT_QUOTES);
$statusMap   = [
    'pending'     => ['label' => 'Menunggu',    'color' => 'secondary'],
    'in_progress' => ['label' => 'Berlangsung', 'color' => 'blue'],
    'done'        => ['label' => 'Selesai',     'color' => 'green'],
    'cancelled'   => ['label' => 'Dibatalkan',  'color' => 'red'],
];
$priorityMap = [
    'low'    => ['label' => 'Rendah', 'color' => 'green'],
    'medium' => ['label' => 'Sedang', 'color' => 'orange'],
    'high'   => ['label' => 'Tinggi', 'color' => 'red'],
];
$st          = $statusMap[$tl['status']]     ?? ['label' => $tl['status'],     'color' => 'secondary'];
$pr          = $priorityMap[$tl['priority']] ?? ['label' => $tl['priority'],   'color' => 'secondary'];
$isAdminLike = Auth::hasRole('admin', 'sekretaris');
$isOverdue   = !empty($tl['due_date']) && $tl['due_date'] < date('Y-m-d') && !in_array($tl['status'], ['done', 'cancelled']);
?>
<meta name="csrf-token" content="<?= $csrfToken ?>">
<div class="tl-hero mb-4"><div class="tl-hero-inner"><nav class="tl-breadcrumb"><a href="<?= $baseUrl ?>/tindak-lanjut">Tindak Lanjut</a><span>Detail</span></nav><div class="d-flex flex-wrap align-items-flex-start justify-content-between gap-3 mt-2"><div><h1 class="tl-hero-title"><?= htmlspecialchars($tl['description']) ?></h1><div class="d-flex flex-wrap align-items-center gap-2 mt-2"><span class="tl-badge tl-badge-<?= $st['color'] ?>"><?= $st['label'] ?></span><span class="tl-badge tl-badge-<?= $pr['color'] ?> tl-badge-outline"><?= $pr['label'] ?></span><?php if ($isOverdue): ?><span class="tl-badge tl-badge-red">Terlambat</span><?php endif; ?></div></div><div class="d-flex flex-wrap gap-2"><a href="<?= $baseUrl ?>/meetings/<?= (int)$tl['meeting_id'] ?>" class="btn tl-btn-ghost">Lihat Meeting</a><?php if ($isAdminLike): ?><button class="btn tl-btn-danger" id="btn-delete-tl">Hapus</button><?php endif; ?></div></div></div></div>
<div class="row g-3"><div class="col-lg-8"><div class="tl-card"><div class="tl-card-header">Progress Notes <span class="tl-count-badge" id="note-count-badge"><?= count($notes) ?></span></div><div id="notes-list" class="tl-notes-list"><?php if (empty($notes)): ?><div class="tl-empty" id="notes-empty"><p>Belum ada catatan progress</p></div><?php else: ?><?php foreach ($notes as $note): ?><div class="tl-note-item" data-note-id="<?= (int)$note['id'] ?>"><div class="tl-note-avatar"><?= strtoupper(mb_substr($note['author_name'], 0, 1)) ?></div><div class="tl-note-body"><div class="tl-note-meta"><span class="tl-note-author"><?= htmlspecialchars($note['author_name']) ?></span><span class="tl-note-time"><?= htmlspecialchars($note['created_at_human'] ?? date('d M Y · H:i', strtotime($note['created_at']))) ?></span></div><div class="tl-note-text"><?= nl2br(htmlspecialchars($note['note'])) ?></div></div><?php if ($note['can_delete']): ?><button class="tl-note-delete btn-delete-note" data-id="<?= (int)$note['id'] ?>">X</button><?php endif; ?></div><?php endforeach; ?><?php endif; ?></div><?php if ($canEdit): ?><div class="tl-note-input-area"><div class="tl-note-input-wrap"><textarea id="note-input" class="tl-note-textarea" rows="2" placeholder="Tulis catatan progress... (Ctrl+Enter untuk kirim)"></textarea><button id="note-submit" class="tl-btn-send">Kirim</button></div></div><?php endif; ?></div></div><div class="col-lg-4"><div class="tl-card mb-3"><div class="tl-card-header">Info Tindak Lanjut</div><div class="tl-info-list"><div class="tl-info-row"><span class="tl-info-label">Meeting</span><a href="<?= $baseUrl ?>/meetings/<?= (int)$tl['meeting_id'] ?>" class="tl-info-link"><?= htmlspecialchars($tl['meeting_title']) ?></a></div><div class="tl-info-row"><span class="tl-info-label">PIC</span><span class="tl-info-val"><?= htmlspecialchars($tl['assignee_name'] ?? '—') ?></span></div><div class="tl-info-row"><span class="tl-info-label">Deadline</span><span class="tl-info-val <?= $isOverdue ? 'tl-text-danger' : '' ?>"><?= !empty($tl['due_date']) ? date('d M Y', strtotime($tl['due_date'])) : '—' ?></span></div><div class="tl-info-row"><span class="tl-info-label">Status</span><span class="tl-badge tl-badge-<?= $st['color'] ?>"><?= $st['label'] ?></span></div><div class="tl-info-row"><span class="tl-info-label">Prioritas</span><span class="tl-badge tl-badge-<?= $pr['color'] ?>"><?= $pr['label'] ?></span></div></div></div><?php if ($canEdit): ?><div class="tl-card mb-3"><div class="tl-card-header">Ubah Status</div><div class="tl-card-body"><div class="d-grid gap-2"><?php foreach ($statusMap as $val => $info): ?><button class="tl-status-btn <?= $tl['status'] === $val ? 'tl-status-btn-active' : '' ?>" data-status="<?= $val ?>"><?= $info['label'] ?></button><?php endforeach; ?></div></div></div><?php endif; ?><div class="tl-card"><div class="tl-card-header">Navigasi</div><div class="tl-nav-links"><a href="<?= $baseUrl ?>/meetings/<?= (int)$tl['meeting_id'] ?>" class="tl-nav-link">Kembali ke Meeting</a><a href="<?= $baseUrl ?>/tindak-lanjut" class="tl-nav-link">Semua Tindak Lanjut</a></div></div></div></div>
<style>.tl-hero{background:linear-gradient(135deg,#7B1C1C 0%,#9B2020 60%,#A83218 100%);border-radius:14px;box-shadow:0 4px 20px rgba(123,28,28,.22);overflow:hidden;position:relative}.tl-hero-inner{padding:1.4rem 1.6rem 1rem}.tl-breadcrumb{display:flex;gap:.3rem;font-size:12px;color:rgba(255,255,255,.65);margin-bottom:.4rem}.tl-breadcrumb a{color:rgba(255,255,255,.75);text-decoration:none}.tl-hero-title{font-size:clamp(15px,2.5vw,22px);font-weight:800;color:#fff;margin:0}.tl-card{border:1px solid #eee;border-radius:14px;overflow:hidden;background:#fff}.tl-card-header{padding:.6rem .9rem;background:#faf4eb;font-weight:700;color:#7B1C1C}.tl-note-item{display:flex;gap:.75rem;padding:.9rem 1rem;border-bottom:1px solid #eee}.tl-note-avatar{width:32px;height:32px;border-radius:50%;background:#7B1C1C;color:#fff;display:flex;align-items:center;justify-content:center;font-weight:700}.tl-note-text{white-space:pre-wrap}.tl-btn-send,.tl-btn-danger,.tl-btn-ghost{padding:.5rem 1rem;border-radius:8px;border:none;cursor:pointer}.tl-btn-send{background:#7B1C1C;color:#fff}.tl-btn-danger{background:#a82515;color:#fff}.tl-btn-ghost{background:#eee}.tl-info-row{padding:.55rem .9rem;border-bottom:1px solid #eee;display:flex;gap:.5rem}.tl-info-label{min-width:90px;font-size:11px;font-weight:700;text-transform:uppercase;color:#666}</style>
<script>
const TL_ID = <?= (int)$tl['id'] ?>;
const BASE_URL = '<?= $baseUrl ?>';
const CSRF_TOKEN = document.querySelector('meta[name="csrf-token"]')?.content ?? '';
function jsonHeaders(){return {'Content-Type':'application/json','X-CSRF-Token':CSRF_TOKEN};}
function setNoteCount(n){const badge=document.getElementById('note-count-badge');if(badge)badge.textContent=n;}
document.querySelectorAll('.tl-status-btn').forEach(btn=>{btn.addEventListener('click',async()=>{const status=btn.dataset.status;const res=await fetch(`${BASE_URL}/tindak-lanjut/${TL_ID}/status`,{method:'POST',headers:jsonHeaders(),body:JSON.stringify({status})});const d=await res.json();if(d.success)location.reload();else alert(d.message||'Gagal menyimpan status');});});
const noteInput=document.getElementById('note-input');const noteSubmit=document.getElementById('note-submit');
async function submitNote(){if(!noteInput||!noteSubmit)return;const note=noteInput.value.trim();if(!note)return;noteSubmit.disabled=true;const res=await fetch(`${BASE_URL}/tindak-lanjut/${TL_ID}/notes`,{method:'POST',headers:jsonHeaders(),body:JSON.stringify({note})});const d=await res.json();if(d.success){noteInput.value='';document.getElementById('notes-empty')?.remove();const n=d.note;const div=document.createElement('div');div.className='tl-note-item';div.dataset.noteId=n.id;div.innerHTML=`<div class="tl-note-avatar">${String(n.author_name||'?').charAt(0).toUpperCase()}</div><div class="tl-note-body"><div class="tl-note-meta"><span class="tl-note-author">${n.author_name}</span><span class="tl-note-time">${n.created_at_human ?? n.created_at}</span></div><div class="tl-note-text">${String(n.note).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;').replace(/\n/g,'<br>')}</div></div>${n.can_delete?`<button class="tl-note-delete btn-delete-note" data-id="${n.id}">X</button>`:''}`;document.getElementById('notes-list').appendChild(div);const delBtn=div.querySelector('.btn-delete-note');if(delBtn)bindDeleteNote(delBtn);setNoteCount(d.note_count);}else alert(d.message||'Gagal mengirim note');noteSubmit.disabled=false;}
noteSubmit?.addEventListener('click',submitNote);noteInput?.addEventListener('keydown',e=>{if(e.key==='Enter'&&e.ctrlKey)submitNote();});
function bindDeleteNote(btn){btn.addEventListener('click',async()=>{if(!confirm('Hapus catatan ini?'))return;const noteId=btn.dataset.id;const res=await fetch(`${BASE_URL}/tindak-lanjut/${TL_ID}/notes/${noteId}/delete`,{method:'POST',headers:jsonHeaders()});const d=await res.json();if(d.success){btn.closest('.tl-note-item').remove();setNoteCount(d.note_count);if(!document.querySelector('.tl-note-item'))document.getElementById('notes-list').innerHTML='<div class="tl-empty" id="notes-empty"><p>Belum ada catatan progress</p></div>';}else alert(d.message||'Gagal menghapus catatan');});}
document.querySelectorAll('.btn-delete-note').forEach(bindDeleteNote);
document.getElementById('btn-delete-tl')?.addEventListener('click',async()=>{if(!confirm('Hapus tindak lanjut ini secara permanen?'))return;const res=await fetch(`${BASE_URL}/tindak-lanjut/${TL_ID}/delete`,{method:'POST',headers:jsonHeaders()});const d=await res.json();if(d.success)location.href=`${BASE_URL}/tindak-lanjut`;else alert(d.message||'Gagal menghapus');});
</script>
